mapper.update:
UPDATE outbox_message
SET status = 'PUBLISHED',
    attempt_count = attempt_count + 1,
    published_at = #{publishedAt}
WHERE id = #{outboxMessageId}
  AND status != 'PUBLISHED'

UPDATE outbox_message
SET status = 'FAILED',
    attempt_count = attempt_count + 1,
    next_attempt_at = #{nextAttemptAt}
WHERE id = #{outboxMessageId}
  AND status != 'PUBLISHED'
